import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, } from '@angular/core';
function defaultInitials(name) {
    return name
        .trim()
        .split(/\s+/)
        .map((part) => part[0]?.toUpperCase() ?? '')
        .slice(0, 2)
        .join('');
}
/**
 * Avatar avec image et fallback sur initiales.
 * Si `src` n'est pas fourni ou échoue à charger, on affiche les
 * initiales calculées depuis `alt` (ou explicites via `initials`).
 */
let PfAvatarComponent = class PfAvatarComponent {
    constructor() {
        this.src = '';
        this.alt = '';
        this.initials = '';
        this.size = 'md';
        this.imageFailed = false;
    }
    get avatarClasses() {
        return `ds-avatar ds-avatar--${this.size}`;
    }
    get displayInitials() {
        return this.initials || defaultInitials(this.alt);
    }
    static { this.propDecorators = {
        src: [{ type: Input }],
        alt: [{ type: Input }],
        initials: [{ type: Input }],
        size: [{ type: Input }]
    }; }
};
PfAvatarComponent = __decorate([
    Component({
        selector: 'pf-avatar',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <span [class]="avatarClasses" role="img" [attr.aria-label]="alt">
      @if (src && !imageFailed) {
        <img
          [src]="src"
          alt=""
          class="ds-avatar__img"
          (error)="imageFailed = true"
        />
      } @else {
        <span aria-hidden="true">{{ displayInitials }}</span>
      }
    </span>
  `,
    })
], PfAvatarComponent);
export { PfAvatarComponent };
